#!/usr/bin/env python3
import matplotlib.pyplot as plt
import numpy as np
from collections import defaultdict
import os
import json

# Create graphs directory if it doesn't exist
script_dir = os.path.dirname(os.path.abspath(__file__))
graphs_dir = os.path.join(script_dir, 'graphs')
os.makedirs(graphs_dir, exist_ok=True)

# Load data from accuracy_data.json (generated by run_mock_pipeline.py)
data_file = os.path.join(script_dir, 'accuracy_data.json')
if os.path.exists(data_file):
    with open(data_file, 'r') as f:
        data = json.load(f)
    print(f"Loaded {len(data)} entries from {data_file}")
else:
    print(f"Error: {data_file} not found. Run run_mock_pipeline.py first to generate benchmark data.")
    exit(1)

# Define difficulty levels and their labels
difficulties = [
    ('easy', 'Easy Difficulty'),
    ('medium', 'Medium Difficulty'),
    ('hard', 'Hard Difficulty')
]

# Sort batch sizes for consistent x-axis
all_batch_sizes = sorted(set(entry['batch_size'] for entry in data))

def analyze_accuracy_data(data, difficulty_filter):
    """Filter data by difficulty and calculate mean + std for each metric.
    
    Handles both individual run entries and aggregated entries:
    - If individual runs exist: uses them to calculate mean/std
    - If only aggregated entries exist: uses the pre-calculated mean/stdev
    """
    filtered = [d for d in data if d['difficulty'] == difficulty_filter]
    
    batch_f1 = defaultdict(list)
    batch_precision = defaultdict(list)
    batch_recall = defaultdict(list)
    batch_f1_agg = {}  # Store aggregated values: {batch_size: (mean, stdev)}
    batch_prec_agg = {}
    batch_rec_agg = {}
    
    for entry in filtered:
        bs = entry['batch_size']
        
        # Check if this is an aggregated entry
        if entry.get('is_aggregated', False):
            # Store aggregated values
            if 'f1_mean' in entry:
                batch_f1_agg[bs] = (entry['f1_mean'], entry.get('f1_stdev', 0))
            if 'precision_mean' in entry:
                batch_prec_agg[bs] = (entry['precision_mean'], entry.get('precision_stdev', 0))
            if 'recall_mean' in entry:
                batch_rec_agg[bs] = (entry['recall_mean'], entry.get('recall_stdev', 0))
        else:
            # Individual run entry - collect raw values
            if 'f1' in entry:
                batch_f1[bs].append(entry['f1'])
            if 'precision' in entry:
                batch_precision[bs].append(entry['precision'])
            if 'recall' in entry:
                batch_recall[bs].append(entry['recall'])
    
    # Combine all batch sizes
    all_batch_sizes = sorted(set(batch_f1.keys()) | set(batch_f1_agg.keys()))
    
    f1_means = []
    f1_stds = []
    prec_means = []
    prec_stds = []
    rec_means = []
    rec_stds = []
    
    for bs in all_batch_sizes:
        # Prefer aggregated values if available, otherwise calculate from individual runs
        if bs in batch_f1_agg:
            f1_means.append(batch_f1_agg[bs][0] * 100)  # Convert to percentage
            f1_stds.append(batch_f1_agg[bs][1] * 100)
        elif batch_f1[bs]:
            f1_means.append(np.mean(batch_f1[bs]) * 100)
            f1_stds.append(np.std(batch_f1[bs]) * 100 if len(batch_f1[bs]) > 1 else 0)
        else:
            f1_means.append(0)
            f1_stds.append(0)
        
        if bs in batch_prec_agg:
            prec_means.append(batch_prec_agg[bs][0] * 100)
            prec_stds.append(batch_prec_agg[bs][1] * 100)
        elif batch_precision[bs]:
            prec_means.append(np.mean(batch_precision[bs]) * 100)
            prec_stds.append(np.std(batch_precision[bs]) * 100 if len(batch_precision[bs]) > 1 else 0)
        else:
            prec_means.append(0)
            prec_stds.append(0)
        
        if bs in batch_rec_agg:
            rec_means.append(batch_rec_agg[bs][0] * 100)
            rec_stds.append(batch_rec_agg[bs][1] * 100)
        elif batch_recall[bs]:
            rec_means.append(np.mean(batch_recall[bs]) * 100)
            rec_stds.append(np.std(batch_recall[bs]) * 100 if len(batch_recall[bs]) > 1 else 0)
        else:
            rec_means.append(0)
            rec_stds.append(0)
    
    return all_batch_sizes, f1_means, f1_stds, prec_means, prec_stds, rec_means, rec_stds

# Create individual graphs for each difficulty level
for diff_key, diff_title in difficulties:
    batch_sizes, f1_means, f1_stds, prec_means, prec_stds, rec_means, rec_stds = analyze_accuracy_data(data, diff_key)
    
    fig, ax = plt.subplots(figsize=(10, 6))
    
    # Plot F1 Score
    ax.errorbar(batch_sizes, f1_means, yerr=f1_stds, fmt='-o', capsize=5,
                linewidth=2, markersize=8, ecolor='red', elinewidth=2,
                label='F1 Score', color='green')
    
    # Plot Precision
    ax.errorbar(batch_sizes, prec_means, yerr=prec_stds, fmt='-s', capsize=5,
                linewidth=2, markersize=8, ecolor='blue', elinewidth=2,
                label='Precision', color='blue')
    
    # Plot Recall
    ax.errorbar(batch_sizes, rec_means, yerr=rec_stds, fmt='-^', capsize=5,
                linewidth=2, markersize=8, ecolor='orange', elinewidth=2,
                label='Recall', color='orange')
    
    ax.set_xlabel('Batch Size (items per batch)', fontsize=11)
    ax.set_ylabel('Score (%)', fontsize=11)
    ax.set_title(f'{diff_title.capitalize()} Difficulty\nF1 Score, Precision & Recall vs Batch Size\n4 Parallel Workers | qwen3-122B-A10B\n2026-05-01 to 2026-05-05', fontsize=10)
    ax.set_xticks(batch_sizes)
    ax.grid(True, alpha=0.3)
    ax.set_ylim(bottom=0, top=100)
    ax.legend(loc='lower right')
    
    # Create filename from difficulty
    filename = f'batching_accuracy_{diff_key}.png'
    output_path = os.path.join(graphs_dir, filename)
    
    plt.savefig(output_path, dpi=150, bbox_inches='tight')
    print(f"Graph saved as '{output_path}'")
    plt.close()

print(f"\nAll {len(difficulties)} graphs saved in '{graphs_dir}' directory.")